import{_ as t,o as a,c as r,ai as o}from"./chunks/framework.AlDDizky.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"};function i(n,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-jskos-vue" tabindex="-1">What is jskos-vue? <a class="header-anchor" href="#what-is-jskos-vue" aria-label="Permalink to &quot;What is jskos-vue?&quot;">​</a></h2><p>jskos-vue is a library for <a href="https://v3.vuejs.org" target="_blank" rel="noreferrer">Vue 3</a> containing components and utilities related to the <a href="https://gbv.github.io/jskos/" target="_blank" rel="noreferrer">JSKOS data format</a> and the <a href="https://coli-conc.gbv.de" target="_blank" rel="noreferrer">coli-conc project</a>. It was developed to make it easier to use JSKOS data and the coli-conc infrastructure in front-end projects.</p><p>Note that it was specifically developed with the needs of our <a href="https://github.com/gbv/cocoda" target="_blank" rel="noreferrer">Cocoda Mapping Tool</a> and <a href="https://github.com/gbv/bartoc.org" target="_blank" rel="noreferrer">BARTOC</a> in mind. So if certain decisions seem odd to you, it is probably because it was needed in one of those projects. Nevertheless feel free to <a href="https://github.com/gbv/jskos-vue/issues" target="_blank" rel="noreferrer">contact us</a> with your questions, suggestions, and use-cases!</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This library provides the following Vue components (plus some helper components and utility functions):</p><ul><li><a href="./components/ItemName.html">ItemName</a> - label or identifier of a JSKOS item</li><li><a href="./components/ItemList.html">ItemList</a> - list of JSKOS items</li><li><a href="./components/ConceptTree.html">ConceptTree</a> - hierarchical browsing of JSKOS concepts</li><li><a href="./components/ItemSuggest.html">ItemSuggest</a> - input field to search and select an item</li><li><a href="./components/ItemDetails.html">ItemDetails</a> - full but condense details of a JSKOS item</li><li><a href="./components/ItemSelected.html">ItemSelected</a> - editable list of JSKOS items</li><li><a href="./components/ItemSelect.html">ItemSelect</a> - form to select multiple JSKOS items</li></ul><h2 id="related-works" tabindex="-1">Related works <a class="header-anchor" href="#related-works" aria-label="Permalink to &quot;Related works&quot;">​</a></h2><p>The <a href="https://github.com/ts4nfdi/terminology-service-suite" target="_blank" rel="noreferrer">TS4NFDI Terminology Service Suite</a> (TSS) provides similar components based on React instead of Vue and TSS includes API calls where jskos-vue leaves this to [cocoda-sdk] or other methods. A very rough correspondence of components and widgets, ignoring conceptual differences:</p><table tabindex="0"><thead><tr><th>jskos-vue</th><th>TSS</th></tr></thead><tbody><tr><td><a href="./components/ItemName.html">ItemName</a></td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_entity-metadata-titlewidget--docs" target="_blank" rel="noreferrer">TitleWidget</a></td></tr><tr><td><a href="./components/ItemList.html">ItemList</a></td><td><em>planned <a href="https://github.com/ts4nfdi/terminology-service-suite/issues/318" target="_blank" rel="noreferrer">EntityListWidget</a></em></td></tr><tr><td><a href="./components/ConceptTree.html">ConceptTree</a></td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_hierarchy-and-graph-hierarchywidget--docs" target="_blank" rel="noreferrer">HierarchyWidget</a></td></tr><tr><td>/</td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_hierarchy-and-graph-graphviewwidget--docs" target="_blank" rel="noreferrer">GraphViewWidget</a></td></tr><tr><td><a href="./components/ItemSuggest.html">ItemSuggest</a></td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/html_search-autocompletewidget--docs" target="_blank" rel="noreferrer">AutocompleteWidget</a></td></tr><tr><td><a href="./components/ItemDetails.html">ItemDetails</a></td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_additional-entity-metadata-entityinfowidget--docs" target="_blank" rel="noreferrer">EntityInfoWidget</a></td></tr><tr><td>/</td><td><a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_additional-entity-metadata-entityrelationswidget--docs" target="_blank" rel="noreferrer">EntityRelationsWidget</a></td></tr></tbody></table><p>In addition [jskos-vue-tabs] is similar to TSS <a href="https://terminology.services.base4nfdi.de/tss/comp/latest/?path=/docs/react_additional-entity-metadata-tabwidget--docs" target="_blank" rel="noreferrer">TabWidget</a>. A mapping Widget is planned in <a href="https://github.com/gbv/jskos-vue/issues/26" target="_blank" rel="noreferrer">both jskos-vue</a> and in <a href="https://github.com/ts4nfdi/terminology-service-suite/issues/305" target="_blank" rel="noreferrer">in TSS</a>.</p>',11)])])}const f=t(s,[["render",i]]);export{p as __pageData,f as default};
